sql:
SELECT player_id
FROM player_transfers
WHERE transfer_date = '2020-01-01';

SELECT SUM(transfers_in_event + transfers_out_event) AS total_transfers
FROM player_transfers
WHERE player_id = (SELECT player_id FROM news_and_updates WHERE news_content = 'Mustafi to miss next three games');

SELECT player_id, event_points, minutes
FROM game_data
ORDER BY event_points DESC;

SELECT match_date, opponent_team, goals_scored, assists
FROM game_data
ORDER BY match_date DESC;

SELECT player_id, MAX(event_points) AS max_event_points
FROM game_data
GROUP BY player_id;

SELECT pt.player_id, t.recent_form
FROM player_transfers pt
JOIN teams t ON pt.transfer_team_to = t.team_name;

SELECT news_title, news_content, news_date, impact
FROM news_and_updates
ORDER BY news_date DESC;

SELECT SUM(transfer_fees) AS total_transfer_fees
FROM player_transfers
WHERE player_id = 2;

SELECT COUNT(transfer_id) AS total_transfers
FROM player_transfers
WHERE transfer_team_to = 'Arsenal';

SELECT player_id, SUM(transfer_fees) AS total_transfer_fees
FROM player_transfers
GROUP BY player_id;
